insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:5-1-1-technology-to-enhance-performance:learn:193694d0', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'learn', 'mcq', 1, '{"readingTitle": "Lighter, better-designed equipment", "reading": "<h4>Why lighter, stiffer equipment helps</h4>\n<ul>\n<li>Modern materials (such as carbon fibre and graphite) let manufacturers build equipment that is <strong>lighter</strong> (less effort to move) and <strong>stiffer</strong> (less energy wasted flexing), so more of the performer''s effort turns into speed, power or control.</li>\n</ul>\n<h4>Named examples</h4>\n<ul>\n<li><strong>Rackets</strong> — modern tennis and badminton rackets use carbon-fibre frames that are lighter and stiffer than older wooden or metal frames, giving players more power and control with less arm fatigue.</li>\n<li><strong>Bikes</strong> — competitive road and track bikes use carbon-fibre frames and wheels that are lighter and more aerodynamic than steel frames, so cyclists produce more speed for the same pedalling effort.</li>\n<li><strong>Footwear</strong> — running shoes with cushioned, energy-returning soles (some with a stiff supportive plate) help runners push off with less wasted effort; football boots are made lighter with studs designed for grip and quick changes of direction.</li>\n</ul>\n<h4>The exam point</h4>\n<ul>\n<li>Explain the mechanism, not just the object: a lighter racket lets a player swing faster with less effort; a stiffer frame transfers more of the rider''s power into speed instead of losing it to flex.</li>\n</ul>", "question": "Why do elite road cyclists usually race on carbon-fibre bike frames rather than heavier steel frames?", "options": ["Steel frames are banned outright by every national governing body across world cycling", "Carbon fibre is lighter and stiffer, so more of the rider''s effort converts into speed", "Carbon-fibre frames are the only frame type that cycling events officially allow riders to use", "Carbon fibre is simply a cheaper material for manufacturers to buy in bulk than steel tubing"]}'::jsonb, '{"answer": 1, "explain": "Carbon fibre is lighter and stiffer than steel, so less of the rider''s effort is wasted and more converts into speed — it is not a rule, a ban or mainly about cost."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:learn:3bef7b58', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'learn', 'mcq', 1, '{"readingTitle": "Data, GPS and video analysis for training and technique", "reading": "<h4>Using data to improve training</h4>\n<ul>\n<li><strong>GPS trackers</strong> (worn in a vest between the shoulder blades) are common in football and rugby. They record distance covered, sprint speed and how hard a player worked in a match or session.</li>\n<li>Coaches use this data to see whether a player is overtraining, undertraining, or ready to return after injury, and to plan the next session''s intensity.</li>\n</ul>\n<h4>Using video to improve technique</h4>\n<ul>\n<li><strong>Video analysis</strong> lets a coach slow footage down, frame by frame, to spot a technical fault a player cannot feel themselves — for example a golfer''s swing plane, a sprinter''s start position, or a swimmer''s stroke technique.</li>\n<li>Comparing footage of a performer over time (or against a model performer) helps target practice on the exact part of the technique that needs work.</li>\n</ul>\n<h4>The exam point</h4>\n<ul>\n<li>The link the exam wants: <em>data/video → spot a specific weakness → adjust training → improved performance.</em> Simply saying \"GPS is used in football\" without this chain earns little.</li>\n</ul>", "question": "What is the main reason a football coach uses GPS-tracking vests during training?", "options": ["To broadcast a player''s exact live location to supporters watching in the stadium seats", "To automatically award a yellow card whenever a player runs at an unsafe sprinting speed", "To collect data on distance and speed so training load can be planned accurately", "To replace the need for a referee to make any decisions at all during the match"]}'::jsonb, '{"answer": 2, "explain": "GPS vests collect data on distance, speed and effort so a coach can plan training load accurately — they do not broadcast locations, issue cards or replace referees."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:misc:16d9fb06', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Any new piece of sports equipment counts as ''technology to enhance performance'', including things like padded headguards or shin pads.</p><p><strong>✅ The correct idea:</strong> This topic is specifically about equipment, clothing or data that helps a performer produce a BETTER performance (more speed, power, accuracy or improved technique) — not equipment whose main job is protecting the performer from injury. A shin pad protecting a footballer is safety technology, not performance technology, even though it is worn during a match. Keep the two ideas separate in an exam answer.</p>", "question": "A boxer wears a padded headguard during sparring. Which type of technology is this?", "options": ["Performance technology, because every headguard is specifically designed to increase the accuracy of each punch thrown", "Safety technology, because its main purpose is to protect the boxer rather than improve performance", "Officiating technology, because referees use it to help decide who has won a bout", "Spectator technology, because it helps the crowd see the fight more clearly from their seats"]}'::jsonb, '{"answer": 1, "explain": "A headguard''s main purpose is protecting the boxer, so it is safety technology — it is not mainly about accuracy, officiating, or the spectator''s view."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:misc:1d19018e', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing ''technology helps performance'' is enough to answer a question on this topic.</p><p><strong>✅ The correct idea:</strong> A vague answer like that earns almost nothing. You must name the actual technology or equipment (for example a carbon-fibre racket, or a GPS vest), the sport it is used in, and the specific effect it has (lighter, so less arm fatigue and more power). Point + named example + effect is what the mark scheme rewards.</p>", "question": "Which answer would earn the most marks on this topic?", "options": ["''Technology helps sport a lot these days in many different ways.''", "''Equipment is important because absolutely everybody uses some kind of equipment whenever they play any sport at all.''", "''Athletes today have access to a very large amount of modern sporting technology.''", "''Carbon-fibre tennis rackets are lighter and stiffer, giving players more power with less arm fatigue.''"]}'::jsonb, '{"answer": 3, "explain": "The last answer names a real technology, links it to a mechanism (lighter/stiffer) and a specific effect (more power). The others are vague statements that name nothing specific."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:misc:36a6bc98', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> GPS trackers and video analysis are only used to measure fitness, never to improve technique.</p><p><strong>✅ The correct idea:</strong> GPS data mainly tracks physical output (distance, speed, effort) so coaches can manage training load — but video analysis is used specifically to improve TECHNIQUE, by spotting faults a performer cannot feel themselves. The two tools do different jobs: one is about physical workload, the other about movement quality.</p>", "question": "What is the key difference between GPS data and video analysis in training?", "options": ["GPS mainly tracks physical output; video analysis mainly targets technique", "There is no real difference at all — the two tools do exactly the same job", "GPS is only used in swimming, while video analysis is only used in football", "Video analysis measures distance covered, while GPS measures technique quality"]}'::jsonb, '{"answer": 0, "explain": "GPS tracks physical workload (distance, speed, effort); video analysis targets technique by spotting faults. They are not identical, not sport-locked, and not swapped round."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tips:d16a8506', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words and mark tariffs for this topic", "reading": "<p>Technology questions are usually short recall or short explain. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name the technology or equipment. \"Identify one piece of equipment used to enhance performance [1]\" = one named item, nothing more.</li>\n<li><strong>Describe</strong> — say what the technology is or does, in your own words, without necessarily explaining why it helps.</li>\n<li><strong>Explain</strong> — give the mechanism. Use the chain: named technology → named sport → the specific effect on performance (speed, power, control or technique).</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants a named example plus one linked effect; [4] wants two developed examples, each with its own effect.</p>", "question": "A question says ''Explain how one piece of equipment enhances performance [2]''. What earns both marks?", "options": ["Naming a general sport without describing any specific piece of equipment at all", "Listing as many different pieces of equipment as you can possibly think of", "Naming the equipment, then linking it to a specific effect on performance", "Describing how much the equipment usually costs to buy in a shop"]}'::jsonb, '{"answer": 2, "explain": "Explain [2] wants the named equipment linked to its effect on performance — a general sport name, a long list, or the cost do not earn these marks."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tips:fcb627a0', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears in the exam + sentence starters", "reading": "<p><strong>Where it shows up:</strong> this topic appears as quick recall in <strong>Section A</strong> (identify/state a technology), and as an applied point in <strong>Section B</strong> scenarios about a named performer or team wanting to improve. It can also feed a <strong>Section C</strong> 8-mark answer discussing technology''s overall impact.</p>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One piece of technology that enhances performance is… because…\"</li>\n<li>\"This helps the performer because it… which means…\"</li>\n<li>\"However, the same technology only helps if…\"</li>\n</ul>", "question": "In a Section B scenario about a named athlete, your equipment example should come from...", "options": ["the scenario you are given, applied to that athlete''s situation", "any sport you personally enjoy watching at the weekend", "a piece of equipment you happen to own yourself", "a famous athlete who is never actually mentioned anywhere in the question"]}'::jsonb, '{"answer": 0, "explain": "Section B is applied — the marks are for using the scenario in front of you, not a general example unconnected to it."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:tips:7573da94', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'tips', 'mcq', 1, '{"readingTitle": "tip — Three habits that lift a performance-technology answer", "reading": "<p>Three punchy tips:</p>\n<ul>\n<li>Always name a <strong>real sport</strong> alongside the technology — \"swimwear\" on its own is vague; \"low-drag racing suits in competitive swimming\" is precise.</li>\n<li>State the <strong>effect</strong>, not just the object: lighter, stiffer, or more aerodynamic → less wasted effort/drag → faster, more powerful or more accurate performance.</li>\n<li>Keep this topic separate from safety, officiating and spectator technology — here, the technology''s job is specifically to make the performer BETTER, not safer or better refereed.</li>\n</ul>", "question": "Which of these best fits THIS topic (technology to enhance performance)?", "options": ["A carbon-fibre racket that is lighter and stiffer, giving more power and control", "A big screen that lets stadium spectators watch a controversial decision replayed", "A padded headguard that protects a boxer''s head during sparring sessions", "A video-review system that helps a referee confirm a marginal decision"]}'::jsonb, '{"answer": 0, "explain": "A lighter, stiffer racket improves the performer''s power and control — the other options are spectator, safety and officiating technology, covered on other pages."}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:fib:c4f10b2c', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'fib', 'fib', 1, '{"question": "Close-fitting, smooth-fabric clothing is described as _____ because it reduces drag through air or water.", "blankOptions": {"B1": ["streamlined", "effort", "stiffer", "fault"]}}'::jsonb, '{"blanks": {"B1": "streamlined"}}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:fib:3c63f5e7', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'fib', 'fib', 1, '{"question": "Carbon-fibre rackets and bike frames are lighter and _____, so less effort is wasted flexing.", "blankOptions": {"B1": ["effort", "vest", "fault", "stiffer"]}}'::jsonb, '{"blanks": {"B1": "stiffer"}}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:fib:e9cdf729', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'fib', 'fib', 1, '{"question": "GPS trackers are usually worn in a _____ between the shoulder blades to record distance and speed.", "blankOptions": {"B1": ["vest", "stiffer", "streamlined", "fault"]}}'::jsonb, '{"blanks": {"B1": "vest"}}'::jsonb),
