('sport-studies:5-1-1-technology-to-enhance-performance:fib:d17aee53', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'fib', 'fib', 1, '{"question": "Cushioned, energy-returning soles help runners push off the ground with less wasted _____.", "blankOptions": {"B1": ["streamlined", "effort", "vest", "fault"]}}'::jsonb, '{"blanks": {"B1": "effort"}}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:match:bb52927e', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Streamlined clothing”?", "options": ["A cushioned running-shoe design that reduces wasted effort when pushing off the ground", "Close-fitting, smooth-fabric kit that reduces drag through air or water", "A lighter, stiffer frame giving more power and control with less arm fatigue", "Slowed-down footage used to spot and correct a specific technical fault"]}'::jsonb, '{"answer": 1, "explain": "“Streamlined clothing” means: Close-fitting, smooth-fabric kit that reduces drag through air or water"}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:match:8bb53e27', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Aerodynamic”?", "options": ["Shaped or designed so air or water flows past with less resistance", "Slowed-down footage used to spot and correct a specific technical fault", "Close-fitting, smooth-fabric kit that reduces drag through air or water", "A cushioned running-shoe design that reduces wasted effort when pushing off the ground"]}'::jsonb, '{"answer": 0, "explain": "“Aerodynamic” means: Shaped or designed so air or water flows past with less resistance"}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:match:2cccaa67', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Carbon-fibre racket”?", "options": ["Shaped or designed so air or water flows past with less resistance", "A lighter, stiffer frame giving more power and control with less arm fatigue", "Close-fitting, smooth-fabric kit that reduces drag through air or water", "Worn between the shoulder blades to record distance and speed for training data"]}'::jsonb, '{"answer": 1, "explain": "“Carbon-fibre racket” means: A lighter, stiffer frame giving more power and control with less arm fatigue"}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:match:a22b1748', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “GPS tracking vest”?", "options": ["A lighter, stiffer frame giving more power and control with less arm fatigue", "Slowed-down footage used to spot and correct a specific technical fault", "Worn between the shoulder blades to record distance and speed for training data", "A cushioned running-shoe design that reduces wasted effort when pushing off the ground"]}'::jsonb, '{"answer": 2, "explain": "“GPS tracking vest” means: Worn between the shoulder blades to record distance and speed for training data"}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:match:7ff11519', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Video analysis”?", "options": ["Slowed-down footage used to spot and correct a specific technical fault", "Close-fitting, smooth-fabric kit that reduces drag through air or water", "Shaped or designed so air or water flows past with less resistance", "Worn between the shoulder blades to record distance and speed for training data"]}'::jsonb, '{"answer": 0, "explain": "“Video analysis” means: Slowed-down footage used to spot and correct a specific technical fault"}'::jsonb),
('sport-studies:5-1-1-technology-to-enhance-performance:match:cc864a00', 'sport-studies', 'sport-studies:5-1-1-technology-to-enhance-performance', '5.1.1 Technology to Enhance Performance', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Energy-returning sole”?", "options": ["A cushioned running-shoe design that reduces wasted effort when pushing off the ground", "A lighter, stiffer frame giving more power and control with less arm fatigue", "Close-fitting, smooth-fabric kit that reduces drag through air or water", "Shaped or designed so air or water flows past with less resistance"]}'::jsonb, '{"answer": 0, "explain": "“Energy-returning sole” means: A cushioned running-shoe design that reduces wasted effort when pushing off the ground"}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:exam:8b6aacec', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'exam', 'mcq', 1, '{"num": "2", "question": "Which piece of technology mainly reduces the force reaching a cyclist''s skull in a fall?", "options": ["A GPS and heart-rate monitor", "A shock-absorbing cycling helmet", "A pitch-side video replay screen", "An instrumented mouthguard"], "hint": "Think about which item is worn on the head and physically absorbs an impact.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — A shock-absorbing cycling helmet.</strong></p>\n<ul>\n<li>The helmet''s outer shell and liner absorb and spread the force of a fall, reducing what reaches the skull.</li>\n<li>A GPS/heart-rate monitor and a video replay screen do not absorb any force, and a mouthguard protects the jaw and teeth, not the skull.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:mcq:7a71f9c6', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'mcq', 'mcq', 1, '{"question": "What is the best definition of ''safety technology'' in sport?", "options": ["Technology that helps officials make faster and more accurate decisions during a contest", "Technology that gives spectators a clearer view of the action inside a stadium", "Technology designed to reduce the likelihood or severity of injury to participants", "Technology that helps a performer train harder and shave time off a personal best"]}'::jsonb, '{"answer": 2, "explain": "Safety technology is aimed at reducing the likelihood or severity of injury. Faster officiating decisions, a clearer spectator view and improved performance are the other three jobs technology can do, not this one."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:mcq:1a17d665', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'mcq', 'mcq', 1, '{"question": "Rugby and boxing performers often wear a mouthguard. What is its main safety purpose?", "options": ["To let the referee check a player''s identity before a contest begins", "To cushion the jaw and teeth from the force of a blow to the head or face", "To help a coach analyse how hard a player has been training that week", "To help review a disputed refereeing decision in slow motion after the match"]}'::jsonb, '{"answer": 1, "explain": "A mouthguard is moulded to a performer''s teeth and cushions the jaw and teeth from a blow. Identity checks, training analysis and reviewing decisions are unrelated jobs."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:mcq:5b1ac5be', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'mcq', 'mcq', 1, '{"question": "Why have many football and hockey clubs replaced old hard artificial pitches with modern 3G/4G surfaces?", "options": ["The synthetic fibres are a more consistent shade of green than a real grass pitch", "It lets a video review system display replays on a big screen beside the pitch", "It guarantees that no match is ever postponed for any reason at any time of year", "The cushioned rubber-crumb layer reduces the impact on joints when a player falls"]}'::jsonb, '{"answer": 3, "explain": "The cushioned layer under a 3G/4G pitch reduces the impact on a falling player''s joints — that is the safety benefit. Pitch colour, replay screens and never postponing matches are not why clubs make the change."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:mcq:c1678408', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'mcq', 'mcq', 1, '{"question": "Some rugby union teams fit sensors inside a scrum cap or mouthguard. What do these sensors mainly do?", "options": ["Measure the force of a blow to the head and alert side-line staff to check the player", "Automatically award a penalty against the other team whenever an illegal high tackle occurs", "Broadcast a player''s exact heart rate live to supporters watching in the stadium", "Record the number of tackles a player makes purely for a post-match highlights reel"]}'::jsonb, '{"answer": 0, "explain": "These sensors measure head-impact force and flag it to side-line medical staff so the player can be checked. Awarding penalties is an officiating job; the sensors are not heart-rate monitors or highlights tools."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:mcq:b15243c0', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'mcq', 'mcq', 1, '{"question": "Why might an endurance athlete train wearing a heart-rate monitor and GPS vest?", "options": ["So a match official can check the athlete has not started running before the whistle", "So spectators at home can follow a live leaderboard of split times during a broadcast", "So coaches can spot overtraining or fatigue early and adjust the session before injury occurs", "So a governing body can confirm the exact make, model and size of the athlete''s footwear before every race begins"]}'::jsonb, '{"answer": 2, "explain": "A heart-rate monitor and GPS vest track workload so a coach can catch overtraining or fatigue before it causes an injury. Checking a false start, entertaining spectators and confirming footwear are unrelated uses."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:mcq:796f266e', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'mcq', 'mcq', 1, '{"question": "In Formula 1, what is the main safety purpose of the HANS device worn by drivers?", "options": ["To let race stewards review a start-line incident in extra slow motion after a race", "To restrain the head and neck and reduce whiplash-type injury in a high-speed crash", "To increase the top speed a car can reach on the longest straight of a circuit", "To give TV commentators live data on a driver''s exact heart rate throughout a race"]}'::jsonb, '{"answer": 1, "explain": "The HANS device links the helmet to the shoulders and restrains the head and neck, reducing whiplash-type injury in a crash. Reviewing incidents, increasing speed and broadcasting heart-rate data are not its job."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tf:dc8896bb', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tf', 'tf', 1, '{"question": "Safety technology in sport is designed to reduce the likelihood or severity of injury."}'::jsonb, '{"answer": true, "explain": "That is the whole point of safety technology — lowering the chance of injury happening, or how serious it turns out to be, for the performer."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tf:9f5169ac', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tf', 'tf', 1, '{"question": "A rugby scrum cap gives a player full protection against concussion."}'::jsonb, '{"answer": false, "explain": "A scrum cap mainly reduces cuts and abrasions from soft padding — it gives little protection against concussion, which is exactly why sport also uses separate impact-detecting technology."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tf:d0d56a63', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tf', 'tf', 1, '{"question": "Modern 3G/4G pitches are used partly because their shock-absorbing layer reduces impact on a player''s joints."}'::jsonb, '{"answer": true, "explain": "The cushioned rubber-crumb layer under a 3G/4G pitch is a genuine safety benefit, reducing joint impact compared with older, harder artificial surfaces."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tf:d9c8a5db', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tf', 'tf', 1, '{"question": "An instrumented mouthguard''s main job is to help a coach plan the following season''s training fixtures."}'::jsonb, '{"answer": false, "explain": "Its job is to measure the force of a head impact and alert side-line staff so the player can be checked — nothing to do with planning a fixture list."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tf:1b529fe9', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tf', 'tf', 1, '{"question": "The HANS device used in Formula 1 helps restrain a driver''s head and neck during a crash."}'::jsonb, '{"answer": true, "explain": "The HANS device links the helmet to the shoulders, restraining the head and neck and reducing whiplash-type injury in a high-speed crash."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tf:cec1e065', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tf', 'tf', 1, '{"question": "Heart-rate and GPS monitoring technology is mainly used to give spectators live entertainment statistics."}'::jsonb, '{"answer": false, "explain": "Its main safety use is tracking a performer''s workload so a coach can catch fatigue or overtraining before it causes injury — any spectator use is a different job of technology."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:learn:9d3c64eb', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'learn', 'mcq', 1, '{"readingTitle": "Why sport invests in safety technology", "reading": "<h4>One of four jobs technology does in sport</h4>\n<ul>\n<li>Technology in sport is usually built for one of four jobs: making performers <strong>better</strong>, keeping performers <strong>safer</strong>, helping officials be <strong>fairer and more accurate</strong>, or making the experience for <strong>spectators</strong> better.</li>\n<li>This page is only about the <strong>safety</strong> job — technology that lowers the chance of a performer getting hurt, or lowers how bad an injury turns out to be. The other three jobs are covered elsewhere and should not be mixed into an answer here.</li>\n</ul>\n<h4>Three broad kinds of safety technology</h4>\n<ul>\n<li><strong>Protective equipment</strong> worn by the performer — helmets, padding, mouthguards and similar items that absorb or block a force before it reaches the body.</li>\n<li><strong>Playing surfaces and equipment design</strong> — pitches, tracks, mats and landing areas engineered so that a fall or a collision does less damage.</li>\n<li><strong>Medical and monitoring technology</strong> — devices that detect an injury (such as a head impact) or track a performer''s condition so problems are caught before they get serious.</li>\n</ul>\n<h4>Why it matters</h4>\n<ul>\n<li>A serious injury can end a performer''s career, and repeated injuries damage trust in a sport. Safety technology lets performers compete and train with a lower level of risk than they otherwise would face.</li>\n</ul>", "question": "Which of these best describes what ''safety technology'' does in sport?", "options": ["Helps spectators see the action more clearly on a big screen inside a stadium", "Lowers the chance or the severity of an injury to a performer", "Helps officials reach faster, more accurate decisions during a contest", "Helps a performer train harder so they can beat a personal best"]}'::jsonb, '{"answer": 1, "explain": "Safety technology is aimed at reducing the likelihood or severity of injury. Spectator viewing, officiating accuracy and performance gains are the other three jobs technology does — not this one."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:learn:26a0ef78', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'learn', 'mcq', 1, '{"readingTitle": "Protective equipment and safer playing surfaces", "reading": "<h4>Protective equipment: helmets, padding, mouthguards</h4>\n<ul>\n<li><strong>Helmets</strong> use a hard outer shell and an energy-absorbing liner to spread and reduce the force of an impact before it reaches the skull. Cycling helmets protect a rider''s head in a fall; cricket helmets add a steel or titanium grille to protect the face from a fast-bowled ball; American football helmets combine a shell with a face cage for collision sport.</li>\n<li><strong>Padding</strong> cushions a specific body part. Hockey and football players wear shin pads; cricket wicketkeepers and batters wear pads and body armour; motorsport drivers wear fire-resistant padded race suits.</li>\n<li><strong>Mouthguards / gum shields</strong> are moulded to a performer''s teeth and cushion the jaw and teeth from an impact. They are common in boxing, rugby and hockey. Some newer mouthguards also contain a sensor — that use is covered in the next card.</li>\n<li><strong>Exam note:</strong> protective equipment mostly <em>absorbs or cushions</em> a force. It reduces certain injuries (cuts, broken teeth, fractures) but does not remove every risk — a scrum cap, for example, gives little protection against concussion.</li>\n</ul>\n<h4>Safer playing surfaces and equipment design</h4>\n<ul>\n<li>Many football and hockey clubs have replaced old, hard artificial pitches with modern <strong>3G/4G surfaces</strong>, which use a cushioned rubber-crumb layer under the fibres to reduce the impact on a player''s joints when they fall or land badly.</li>\n<li>Athletics tracks now use a springy, shock-absorbing surface rather than hard cinder, and events like high jump and pole vault use deep <strong>crash mats or landing airbags</strong> so a fall from height does not cause serious injury.</li>\n<li>Gymnastics uses sprung floors and thick crash mats for the same reason, and some pitches use padded goalposts or posts to reduce injury from a collision.</li>\n</ul>", "question": "What is the main safety purpose of a mouthguard worn in boxing or rugby?", "options": ["To cushion the jaw and teeth from the force of a blow to the head or face", "To let the referee check a player''s identity before a contest begins", "To help a coach analyse exactly how hard a player has been training that particular week", "To make a fast decision on a disputed refereeing call during a match"]}'::jsonb, '{"answer": 0, "explain": "A mouthguard is moulded to a performer''s teeth and cushions the jaw and teeth from an impact. It has nothing to do with identity checks, training analysis or officiating decisions."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:learn:e9844411', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'learn', 'mcq', 1, '{"readingTitle": "Detecting concussion and monitoring player welfare", "reading": "<h4>Detecting a head injury</h4>\n<ul>\n<li>Some rugby union teams now fit a sensor inside a scrum cap or mouthguard. The sensor measures the <strong>force of a blow to the head</strong> and sends an alert to side-line medical staff so they know to check that player straight away, rather than waiting for the player to report symptoms themselves.</li>\n<li>Sport also uses a structured, timed <strong>pitch-side head-injury assessment</strong> — medical staff use a fixed set of checks to judge whether a player who has taken a blow can safely return to play, instead of relying on a quick, informal look.</li>\n</ul>\n<h4>Medical and monitoring technology</h4>\n<ul>\n<li>Endurance athletes and team-sport players often train and compete wearing a <strong>heart-rate monitor and GPS vest</strong>. These track how hard a performer is working, so a coach can spot overtraining or fatigue building up and adjust a session before it causes an injury.</li>\n<li>In motorsport, Formula 1 drivers wear a <strong>HANS device</strong> (a rigid frame linking the helmet to the shoulders) which restrains the head and neck and reduces whiplash-type injury in a high-speed crash. Some race suits and gloves also carry biometric sensors that tell medical staff a driver''s condition seconds after an impact.</li>\n</ul>\n<h4>Exam skill: name the sport AND the specific benefit</h4>\n<ul>\n<li>A weak answer says \"technology helps safety.\" A strong answer names the technology, the sport, and exactly what it protects against or detects — for example, \"an instrumented mouthguard in rugby union measures head-impact force and alerts side-line staff to check the player.\"</li>\n</ul>", "question": "A sensor fitted inside a rugby player''s mouthguard is mainly used to...", "options": ["broadcast the player''s exact heart rate live to supporters in the stadium", "measure the force of a head impact and alert side-line staff to check the player", "automatically award a penalty against the opposing team whenever an illegal tackle occurs in play", "record tackle numbers purely so they can be used in a highlights programme"]}'::jsonb, '{"answer": 1, "explain": "Instrumented mouthguards measure head-impact force and flag it to side-line medical staff — a safety use. Awarding penalties is an officiating job, not a safety one, and the sensor is not a heart-rate or highlights tool."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:misc:e15bd133', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Any padding a performer wears counts as the same kind of safety technology as an instrumented mouthguard.</p><p><strong>✅ The correct idea:</strong> They do two different jobs. Protective equipment (helmets, pads, mouthguards, padded goalposts) mostly ABSORBS or CUSHIONS a force before it does damage. Detection and monitoring technology (an instrumented mouthguard''s sensor, a heart-rate/GPS monitor) does not stop the force — it DETECTS an impact, or tracks a condition, and alerts someone. A strong answer says which job a piece of technology is actually doing.</p>", "question": "What is the key difference between protective equipment and detection/monitoring technology?", "options": ["There is no real difference between the two types of technology at all", "Protective equipment cushions a force; monitoring technology detects and alerts staff instead", "Protective equipment is only ever used by professional motorsport teams, never in any other sport", "Monitoring technology removes the need for a performer to ever wear protective equipment again"]}'::jsonb, '{"answer": 1, "explain": "One kind reduces the force reaching the body; the other kind detects a problem (an impact, or a worrying condition) and flags it, rather than physically absorbing anything."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:misc:570128c6', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Once a rugby player is wearing a scrum cap or mouthguard, head injury basically stops being a risk.</p><p><strong>✅ The correct idea:</strong> Protective gear cushions certain impacts (cuts, jaw and tooth injury) but does not remove concussion risk. That is exactly why sport ALSO uses separate detection technology — impact sensors and structured pitch-side head-injury checks — as well as protective gear. Equipment and detection technology work together; neither one on its own makes a performer fully safe.</p>", "question": "Why does sport use head-impact sensors and pitch-side checks as well as protective headwear?", "options": ["Because protective headwear alone does not remove the risk of concussion", "Because protective headwear has been banned completely in most contact sports now", "Because sensors are only ever used to replace worn-out scrum caps", "Because pitch-side checks are required only for spectators, not players"]}'::jsonb, '{"answer": 0, "explain": "Protective gear reduces some injuries but does not eliminate concussion risk, so detection technology and structured checks are used alongside it, not instead of it."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:misc:4f2b4077', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Because this topic is about technology and safety, goal-line technology and video review are good examples to use in an answer here.</p><p><strong>✅ The correct idea:</strong> Goal-line technology and video review help an OFFICIAL make a fair, accurate decision — that is a different job of technology from SAFETY. Using them in a safety-technology answer describes the wrong page''s content and will not earn the marks. Keep officiating examples (like video review) out of a question specifically about safety.</p>", "question": "Why would goal-line technology be the wrong example to use in a question specifically about safety technology?", "options": ["It does not exist in real sport", "It is officiating technology, aimed at fair and accurate decisions, not safety", "It is too expensive for most amateur clubs to install and maintain properly", "It has exactly the same safety purpose in every sport as an instrumented mouthguard"]}'::jsonb, '{"answer": 1, "explain": "Goal-line technology supports officiating decisions, not player safety, so using it as a safety example answers a different question and would not be credited here."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tips:e3878620', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Safety-technology questions are usually short recall or short application. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"State one piece of technology used to increase safety\" = one named example, nothing more. 1 mark.</li>\n<li><strong>Describe</strong> — say what it is or does. \"Describe how an instrumented mouthguard increases safety\" = explain what the sensor detects.</li>\n<li><strong>Explain</strong> — give a reason, using the word <em>because</em>. \"Explain why a 3G pitch is safer than an old artificial pitch\" = the feature <em>plus</em> the injury it reduces.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one named example; [2–4] wants the example PLUS how it works or why it helps; higher tariffs in Section B/C want it applied to a named sport or scenario.</p>", "question": "A question says: ''Identify one piece of technology that can increase safety in sport [1]''. What is the safest answer?", "options": ["A full paragraph explaining several different technologies", "One named piece of technology", "A list of every safety technology you can remember", "An explanation of how officiating technology works instead"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [1] wants one named example. A long explanation, a long list, or an officiating example all waste the mark or answer the wrong question."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tips:16018eb6', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the sport AND the specific safety benefit", "reading": "<p>The most common way to lose marks here is staying vague. Build every answer as <strong>technology → sport → specific benefit</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Technology makes sport safer.\"</li>\n<li><strong>✅ full marks:</strong> \"An instrumented mouthguard in rugby union measures the force of a head impact and alerts side-line staff to check the player.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you will usually be given a scenario. Use a detail <em>from that scenario</em> — the sport it names, the problem it describes — rather than a generic example.</p>", "question": "In a Section B scenario about a specific club or sport, your safety-technology example should come from...", "options": ["any sport you happen to prefer, regardless of the scenario", "the scenario you are actually given", "a piece of officiating technology instead", "a technology that improves performance rather than safety"]}'::jsonb, '{"answer": 1, "explain": "Section B rewards applying your knowledge to the scenario given, not a generic or unrelated example."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:tips:62d4f4f0', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> safety technology appears as quick recall in <strong>Section A</strong> (name a technology, name a benefit), as an applied point in <strong>Section B</strong> scenarios about a club or performer, and it can feed a <strong>Section C</strong> discussion on how effective technology has been for a sport overall.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Keep a mental list of three types: protective equipment, safer surfaces/equipment design, and detection/monitoring technology — you can always pull an example from one of the three.</li>\n<li>Never let a safety answer drift into officiating (video review, goal-line technology) — that is a different page''s content and will not be credited.</li>\n<li>Remember protective equipment reduces some injuries but does not remove all risk — that is a strong evaluation point for a longer answer.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way technology increases safety in this sport is… because…\"</li>\n<li>\"This matters because, without it, a performer would risk…\"</li>\n<li>\"However, this technology does not remove every risk, because…\"</li>\n</ul>", "question": "Why is ''protective equipment reduces some injuries but not all risk'' a useful evaluation point?", "options": ["It shows understanding that safety technology has real limits, not just benefits", "It proves that safety technology should never be used in any sport at all, under any circumstances", "It fills space without adding anything useful to the answer", "It replaces the need to name any technology in the answer"]}'::jsonb, '{"answer": 0, "explain": "Noticing the limits of a technology (not just its benefit) shows deeper understanding — exactly the kind of point that lifts a Section C answer beyond a simple list."}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:fib:2462a30c', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'fib', 'fib', 1, '{"question": "Cricket and American football helmets use a reinforced shell to reduce the _____ of a blow reaching the head.", "blankOptions": {"B1": ["joints", "neck", "side-line", "force"]}}'::jsonb, '{"blanks": {"B1": "force"}}'::jsonb),
