('sport-studies:5-1-2-technology-to-increase-safety:match:46b27d69', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Instrumented mouthguard”?", "options": ["An artificial pitch with a cushioned layer that lowers the impact on a falling player''s joints", "A wearable that tracks a performer''s workload so fatigue is spotted before it causes injury", "A device fitted with a sensor that measures the force of a blow to the head", "Padded landing equipment that reduces injury from a fall in gymnastics or athletics"]}'::jsonb, '{"answer": 2, "explain": "“Instrumented mouthguard” means: A device fitted with a sensor that measures the force of a blow to the head"}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:match:96c12921', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Shock-absorbing helmet”?", "options": ["Padded landing equipment that reduces injury from a fall in gymnastics or athletics", "An artificial pitch with a cushioned layer that lowers the impact on a falling player''s joints", "A wearable that tracks a performer''s workload so fatigue is spotted before it causes injury", "Headwear with an energy-absorbing liner that reduces the force reaching the skull"]}'::jsonb, '{"answer": 3, "explain": "“Shock-absorbing helmet” means: Headwear with an energy-absorbing liner that reduces the force reaching the skull"}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:match:f582883a', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “3G/4G playing surface”?", "options": ["An artificial pitch with a cushioned layer that lowers the impact on a falling player''s joints", "A device fitted with a sensor that measures the force of a blow to the head", "Padded landing equipment that reduces injury from a fall in gymnastics or athletics", "Motorsport equipment that restrains the head and neck during a sudden, high-speed crash"]}'::jsonb, '{"answer": 0, "explain": "“3G/4G playing surface” means: An artificial pitch with a cushioned layer that lowers the impact on a falling player''s joints"}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:match:410219cf', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “HANS device”?", "options": ["Headwear with an energy-absorbing liner that reduces the force reaching the skull", "Motorsport equipment that restrains the head and neck during a sudden, high-speed crash", "A wearable that tracks a performer''s workload so fatigue is spotted before it causes injury", "Padded landing equipment that reduces injury from a fall in gymnastics or athletics"]}'::jsonb, '{"answer": 1, "explain": "“HANS device” means: Motorsport equipment that restrains the head and neck during a sudden, high-speed crash"}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:match:4933a9f3', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Heart-rate and GPS monitor”?", "options": ["A device fitted with a sensor that measures the force of a blow to the head", "A wearable that tracks a performer''s workload so fatigue is spotted before it causes injury", "An artificial pitch with a cushioned layer that lowers the impact on a falling player''s joints", "Padded landing equipment that reduces injury from a fall in gymnastics or athletics"]}'::jsonb, '{"answer": 1, "explain": "“Heart-rate and GPS monitor” means: A wearable that tracks a performer''s workload so fatigue is spotted before it causes injury"}'::jsonb),
('sport-studies:5-1-2-technology-to-increase-safety:match:de002021', 'sport-studies', 'sport-studies:5-1-2-technology-to-increase-safety', '5.1.2 Technology to Increase Safety', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Crash mat / landing airbag”?", "options": ["Padded landing equipment that reduces injury from a fall in gymnastics or athletics", "A wearable that tracks a performer''s workload so fatigue is spotted before it causes injury", "Headwear with an energy-absorbing liner that reduces the force reaching the skull", "Motorsport equipment that restrains the head and neck during a sudden, high-speed crash"]}'::jsonb, '{"answer": 0, "explain": "“Crash mat / landing airbag” means: Padded landing equipment that reduces injury from a fall in gymnastics or athletics"}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:exam:e773fa24', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these best describes what goal-line technology does in football?", "options": ["Confirms whether the whole ball has crossed the goal line, using cameras or sensors around the goal", "Reviews footage of penalty decisions and cases of mistaken identity for the referee to consider", "Advises the referee on rugby union tries and serious foul play from the touchline", "Lets a cricket player formally challenge an umpire''s lbw or catch decision using video replay and ball-tracking evidence"], "hint": "Think about the one specific job goal-line technology does — and only in football.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — confirms whether the whole ball has crossed the goal line, using cameras or sensors around the goal.</strong></p>\n<ul>\n<li>This is goal-line technology''s one specific job in football.</li>\n<li>The other options describe VAR (penalties/mistaken identity), the TMO (rugby union) and DRS (cricket) — different systems, different sports.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:mcq:6bf6fa13', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'mcq', 'mcq', 1, '{"question": "Which of these is something VAR (Video Assistant Referee) checks in football?", "options": ["Whether a player''s boots meet the technical specifications set by the competition organisers", "Goals, penalty decisions, red cards and cases of mistaken identity", "The exact wind speed recorded pitch-side during the match", "How many replacement footballs are stored behind each goal"]}'::jsonb, '{"answer": 1, "explain": "VAR reviews goals, penalties, red cards and mistaken identity — it is not used to check equipment, weather or spare footballs."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:mcq:6abccf0d', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'mcq', 'mcq', 1, '{"question": "What does the TMO (Television Match Official) do in rugby union?", "options": ["Sells tickets for international rugby union fixtures at the stadium entrance", "Coaches the players during every break in play by showing them video replays on a pitch-side screen", "Watches video replays and advises the on-field referee about tries and serious foul play", "Times each half of the match using a handheld stopwatch on the touchline"]}'::jsonb, '{"answer": 2, "explain": "The TMO is an off-field official who reviews video and advises the referee on tries and serious foul play — not a coach, ticket seller or timekeeper."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:mcq:1b4addad', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'mcq', 'mcq', 1, '{"question": "How does goal-line technology confirm a goal in football?", "options": ["By asking a panel of supporters in the crowd to vote on whether they believe the ball crossed the line", "By replaying slow-motion footage exclusively to television pundits sitting in a studio, without informing the match officials at all", "By measuring the exact weight of the match ball before kick-off", "By using cameras or sensors around the goal to detect the ball crossing the line and signalling the referee"]}'::jsonb, '{"answer": 3, "explain": "Sensors or cameras around the goal detect the ball fully crossing the line and send a signal straight to the referee — there is no crowd vote, weigh-in, or studio-only replay."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:mcq:f07cb6ef', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'mcq', 'mcq', 1, '{"question": "What does Hawk-Eye (ball-tracking technology) show in tennis?", "options": ["Whether a serve or shot landed inside or outside the line when a player challenges the call", "The exact heart rate of each player during a five-set match", "Whether the crowd noise exceeded the stadium''s permitted decibel limit", "The manufacturer of the tennis balls being used in the tournament, printed on-screen for viewers at home"]}'::jsonb, '{"answer": 0, "explain": "Hawk-Eye tracks the ball''s path to show whether it landed in or out — it does not measure heart rate, crowd noise, or display the ball brand."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:mcq:a9c93a5d', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'mcq', 'mcq', 1, '{"question": "Why is a photo-finish camera used at the end of an athletics sprint?", "options": ["Because it allows the race organisers to sell far more advertising space around the finish line during a televised event", "Because human eyes cannot reliably separate sprinters who finish within hundredths of a second of one another", "Because it decides which athlete receives a post-race media interview first", "Because it replaces the need for a starting gun at the beginning of the race"]}'::jsonb, '{"answer": 1, "explain": "A photo-finish camera exists because the human eye cannot reliably split sprinters finishing hundredths of a second apart — it is about accuracy, not advertising, interviews or starts."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:mcq:3ac901d4', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'mcq', 'mcq', 1, '{"question": "What do video review, goal-line technology and electronic timing all have in common?", "options": ["They all rely on the crowd''s reaction to decide whether a call was correct", "They all give officials extra, evidence-based information so decisions are more accurate and fair", "They all replace officials completely so that no human judgement is ever required at any point during a match or race", "They are all only used once every four years at major international events"]}'::jsonb, '{"answer": 1, "explain": "Each technology gives officials additional recorded or automatic evidence to make more accurate, fairer decisions — none of them hand the decision to the crowd or remove officials entirely."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tf:0cba2d70', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tf', 'tf', 1, '{"question": "VAR reviews replay footage, but the final decision in football is still made by the on-field referee."}'::jsonb, '{"answer": true, "explain": "VAR advises using recorded footage — the referee watches the review and makes the final call, so the human decision-maker is not removed."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tf:5ab16fdd', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tf', 'tf', 1, '{"question": "The TMO in rugby union is a player on the pitch who reviews decisions during a break in play."}'::jsonb, '{"answer": false, "explain": "The TMO is an off-field official, not a player — they watch video feeds and advise the referee on tries and serious foul play."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tf:d21688b5', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tf', 'tf', 1, '{"question": "Goal-line technology can confirm a goal even when the ball crosses the line too fast for officials to see clearly."}'::jsonb, '{"answer": true, "explain": "That is exactly why it exists — cameras and sensors detect the crossing far faster and more reliably than the human eye can from pitch-side."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tf:0b431397', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tf', 'tf', 1, '{"question": "Hawk-Eye ball-tracking is the technology football uses to confirm whether a goal has been scored."}'::jsonb, '{"answer": false, "explain": "Football uses goal-line technology for that job. Hawk-Eye ball-tracking is used in sports like tennis and cricket to show where a ball landed or was heading."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tf:b95f2b6c', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tf', 'tf', 1, '{"question": "Electronic timing in athletics removes human reaction-time error from the recorded result."}'::jsonb, '{"answer": true, "explain": "Because the system starts and stops automatically, it takes the timekeeper''s own reaction speed out of the recorded time completely."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tf:b14c9efc', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tf', 'tf', 1, '{"question": "A photo-finish camera is needed because human eyes can reliably separate two sprinters who finish a hundredth of a second apart."}'::jsonb, '{"answer": false, "explain": "The opposite is true — human eyes cannot reliably separate finishes that close, which is precisely why the camera is needed."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:learn:44e25ba4', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'learn', 'mcq', 1, '{"readingTitle": "Video review technology: giving officials a second look", "reading": "<h4>What it does</h4>\n<ul>\n<li>Video review technology lets officials pause and study a <strong>replay</strong> of a contentious moment, often in slow motion and from more than one camera angle, instead of relying only on what they saw live at full speed.</li>\n<li>This matters because live sport moves fast — a single glance from one angle can miss a foul, an offside position, or contact that happened out of sight.</li>\n</ul>\n<h4>Named examples you must know</h4>\n<ul>\n<li><strong>TMO (Television Match Official)</strong> in rugby union — an off-field official who watches video feeds and advises the referee on tries and serious foul play.</li>\n<li><strong>VAR (Video Assistant Referee)</strong> in football — a team of officials who review footage of goals, penalties, red cards and mistaken identity, then advise the referee, who still makes the final decision.</li>\n<li><strong>DRS (Decision Review System)</strong> in cricket — lets a player formally challenge an umpire''s decision (such as lbw or a catch), which is then checked using replays and ball-tracking data.</li>\n</ul>\n<h4>Why it increases fair play</h4>\n<ul>\n<li>It gives officials extra recorded evidence before a big decision is finalised, so a mistake made at normal speed can be corrected.</li>\n<li>Players and fans can see that a decision was checked properly, which builds trust that the result was fair.</li>\n</ul>", "question": "What is the main purpose of video review technology such as VAR or the TMO?", "options": ["To let officials check a contentious decision using recorded replay footage before it is finalised", "To automatically overturn any refereeing decision the instant a TV camera happens to catch a replay of it", "To replace the referee completely so that no human ever has to make a decision during a match", "To slow every match down by pausing play the moment any fan on social media disagrees with a call"]}'::jsonb, '{"answer": 0, "explain": "Video review gives officials extra recorded evidence to check a decision — it does not remove the referee, and no decision is made automatically or by outside fans."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:learn:3dddbfbe', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'learn', 'mcq', 1, '{"readingTitle": "Goal-line and ball-tracking technology: proving exactly where the ball went", "reading": "<h4>What it does</h4>\n<ul>\n<li>Goal-line technology uses cameras or sensors positioned around the goal to detect the exact moment the whole ball crosses the line, sending an instant signal to the referee''s watch.</li>\n<li>Ball-tracking technology follows the path of a ball across many camera frames per second and can show precisely where it landed or where it was heading.</li>\n</ul>\n<h4>Named examples</h4>\n<ul>\n<li><strong>Goal-line technology</strong> in football — confirms whether a goal should be given when the ball crosses the line at speed and players'' bodies block the officials'' view.</li>\n<li><strong>Hawk-Eye (ball-tracking)</strong> in tennis — shows whether a serve or shot landed inside or outside the line when a player challenges the call.</li>\n<li><strong>Ball-tracking</strong> in cricket — part of DRS, used to predict the ball''s path and help decide lbw appeals.</li>\n</ul>\n<h4>Why it increases accuracy</h4>\n<ul>\n<li>A ball can cross a line in a fraction of a second — far faster than the human eye can judge reliably from pitch-side or on the baseline.</li>\n<li>Because the technology gives an instant, evidence-based answer, the correct decision is given even in very close, fast-moving situations.</li>\n</ul>", "question": "Why is goal-line technology needed in football, even though officials are already watching the game?", "options": ["Because the ball can cross the line faster than the human eye can reliably judge when players block the view", "Because a photo-finish camera can only ever be used to separate sprinters at the end of an athletics race, never in football", "Because referees are not permitted to make any decisions at all about goals under the laws of the game", "Because it gives spectators extra time to buy refreshments while officials wait for a signal"]}'::jsonb, '{"answer": 0, "explain": "The ball can cross the line too fast for a human to judge reliably, especially when players block the view — goal-line technology exists for exactly that gap, not because referees are banned from deciding goals."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:learn:975ff59a', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'learn', 'mcq', 1, '{"readingTitle": "Electronic timing and measurement: officiating close finishes fairly", "reading": "<h4>What it does</h4>\n<ul>\n<li>In sports decided by very small differences in time or distance, electronic timing and measurement systems record results far more precisely than a human with a stopwatch or the naked eye ever could.</li>\n<li>Electronic timing usually starts automatically from the starting gun or blocks and stops the instant a competitor''s body or a touchpad crosses the line, removing human reaction-time error from the recorded result.</li>\n</ul>\n<h4>Named examples</h4>\n<ul>\n<li><strong>Photo-finish cameras</strong> in athletics — take a continuous image of the finish line so officials can separate sprinters who finish within hundredths of a second of one another.</li>\n<li><strong>Electronic touchpads</strong> in swimming — detect the exact moment each swimmer touches the wall, ending any argument over who finished first.</li>\n</ul>\n<h4>Why it increases fair play</h4>\n<ul>\n<li>A human judge glancing at a finish line simply cannot separate athletes who cross within a hundredth of a second of each other — the camera can.</li>\n<li>Because every competitor is timed by the same automatic system, no athlete can be given an unfair advantage or disadvantage by an official''s reaction time.</li>\n</ul>", "question": "Why do athletics and swimming rely on electronic timing rather than an official''s stopwatch alone?", "options": ["Because electronic timing removes human reaction-time error and can separate finishes within hundredths of a second", "Because a stopwatch is completely banned under the official rules of every athletics and swimming competition in the world", "Because officials are no longer allowed to attend athletics or swimming events once the race has started", "Because it makes each race last considerably longer than it otherwise would without the equipment"]}'::jsonb, '{"answer": 0, "explain": "Electronic timing removes human reaction-time error and can separate finishes within hundredths of a second — something a stopwatch or the naked eye cannot do reliably."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:misc:bd0125d4', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> VAR takes the decision away from the referee completely — the computer decides.</p><p><strong>✅ The correct idea:</strong> VAR only reviews and advises. In football, the on-field referee still watches the review footage and makes the final decision — the technology provides extra evidence, it does not decide the outcome on its own.</p>", "question": "Who makes the final decision after a VAR review in football?", "options": ["The on-field referee, using the additional evidence from the replay", "A computer program that calculates the outcome automatically without any human input at all", "The two team captains, who vote together on the correct outcome", "The television broadcaster''s commentary team covering the match"]}'::jsonb, '{"answer": 0, "explain": "The referee reviews the footage and still makes the call — VAR supplies evidence, it does not replace human judgement, a vote, or the commentary team."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:misc:47261d0b', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Goal-line technology and the TMO are basically the same system, just used in different sports.</p><p><strong>✅ The correct idea:</strong> They are different systems doing different jobs. Goal-line technology is specific to football and only checks whether the ball fully crossed the line. The TMO is a rugby union official who reviews general video replay of tries and foul play — not a single shared piece of equipment.</p>", "question": "What is the key difference between goal-line technology and the TMO?", "options": ["Goal-line technology is a football system checking the ball crossing the line; the TMO is a rugby union official reviewing footage", "There is no real difference at all — they are exactly the same system used in every single sport", "Goal-line technology is used only in cricket to time each ball that is bowled, while the TMO is a type of stopwatch used only in swimming", "The TMO is a type of camera, while goal-line technology is a type of human official standing pitch-side"]}'::jsonb, '{"answer": 0, "explain": "Goal-line technology is a football-specific sensor system for one narrow job (the line crossing); the TMO is a rugby union person reviewing broader video evidence — not interchangeable, and not the reverse of what the other options claim."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:misc:67500031', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All of this technology is only there to slow the game down and annoy players and fans.</p><p><strong>✅ The correct idea:</strong> That criticism does exist, but the core purpose of video review, goal-line and timing technology is to increase the accuracy of decisions and support fair play — giving officials extra evidence so the correct outcome is more likely to be given. Its wider effect on the flow of the game is a separate debate.</p>", "question": "What is the core purpose of officiating technology like VAR, goal-line technology and electronic timing?", "options": ["To increase the accuracy of decisions and support fair play by giving officials extra evidence", "To make the sport last as long as possible so that broadcasters can sell more advertising space", "To remove all officials from professional sport within the next few years", "To give spectators something new to complain about during a match"]}'::jsonb, '{"answer": 0, "explain": "The purpose taught here is accuracy and fairness — extra advertising time, removing officials and giving fans something to complain about are not why this technology exists."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tips:cc1b5017', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Officiating-technology questions test recall and application. Match your answer length to the command word:</p>\n<ul>\n<li><strong>State / Identify</strong> — just name the technology. \"State one technology that helps officials [1]\" = one name, nothing more.</li>\n<li><strong>Explain</strong> — say what the technology does, <em>then</em> use <em>because</em> to link it to accuracy or fairness. Name plus reason, not name alone.</li>\n<li><strong>Discuss / Evaluate</strong> (8 marks) — apply the technology to the scenario, weigh a benefit against a limitation (cost, or that a human still interprets the footage), then give a judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] often wants a technology plus its sport, or two named technologies; [4] in Section B wants each technology linked to the scenario.</p>", "question": "A question says: ''State two technologies used to help officials make accurate decisions [2]''. What is the safest answer?", "options": ["A long paragraph explaining one piece of technology in great detail", "Two named technologies, one for each mark", "Six different named technologies, even though only two marks are on offer", "One technology explained fully, with no second one given at all"]}'::jsonb, '{"answer": 1, "explain": "''State'' + [2] = two names, one mark each. A long explanation of one, six names, or only one name each miss the tariff."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tips:cbaf7c67', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the technology AND link it to accuracy or fairness", "reading": "<p>The most common way to lose marks here is stopping at the name. Build every answer as <strong>technology → what it does → why that improves accuracy or fairness</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"VAR.\"</li>\n<li><strong>✅ full marks:</strong> \"VAR lets officials review footage of an incident, so a clear mistake made at full speed can be corrected before a goal is given.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you get a scenario (a named match, league or event). Marks come from linking your technology to the <em>specific</em> problem in that scenario — not a general example.</p>", "question": "In a Section B scenario about a specific match or event, your example of technology should…", "options": ["ignore the scenario completely and describe your favourite team instead", "list as many different technologies as you can recall, regardless of the scenario", "link to the specific detail given in the scenario you have been given", "repeat the question word for word without adding any new information"]}'::jsonb, '{"answer": 2, "explain": "Section B is applied — the marks are for using the detail in front of you, not for ignoring it, listing everything you know, or restating the question."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:tips:65e50e5e', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears in the exam + sentence starters", "reading": "<p><strong>Where it shows up:</strong> quick recall of named technologies in <strong>Section A</strong>; an applied scenario in <strong>Section B</strong> asking how a technology would help officials in a specific situation; and a balanced <strong>Section C</strong> discussion of how far this technology actually delivers fairer, more accurate officiating.</p>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One piece of technology that could help here is… because…\"</li>\n<li>\"This would improve accuracy by… so the official could…\"</li>\n<li>\"However, the extent to which this guarantees a fair decision depends on…\"</li>\n</ul>", "question": "Why is ''however, the extent to which this guarantees fairness depends on…'' a useful sentence starter in an 8-mark answer?", "options": ["It fills space without needing any real content behind it", "It signals that you are about to weigh up a limitation before giving a judgement", "It means you never need to reach an overall judgement at the end", "It completely replaces the need to mention any named piece of technology or sport at all in your answer"]}'::jsonb, '{"answer": 1, "explain": "The phrase signals a shift into evaluation — weighing a limitation before the final judgement — which is exactly what Section C rewards, not empty filler or an excuse to skip named technology."}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:fib:29586f18', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'fib', 'fib', 1, '{"question": "VAR stands for Video _____ Referee, and reviews goals, penalties, red cards and mistaken identity.", "blankOptions": {"B1": ["ball", "Assistant", "hundredths", "signal"]}}'::jsonb, '{"blanks": {"B1": "Assistant"}}'::jsonb),
