('sport-studies:5-1-3-technology-and-officiating:fib:78204e0f', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'fib', 'fib', 1, '{"question": "Hawk-Eye is a _____-tracking system used in tennis and cricket to show exactly where the ball went.", "blankOptions": {"B1": ["signal", "replays", "hundredths", "ball"]}}'::jsonb, '{"blanks": {"B1": "ball"}}'::jsonb),
