('sport-studies:5-1-3-technology-and-officiating:match:73872567', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “VAR (Video Assistant Referee)”?", "options": ["An off-field official in rugby union who checks tries and serious foul play using video replays", "A cricket system letting a player challenge an umpire''s decision, checked using replays and ball-tracking", "Camera and automatic timing systems in athletics and swimming that separate finishes within hundredths of a second", "A team of officials in football who review footage of goals, penalties, red cards and mistaken identity"]}'::jsonb, '{"answer": 3, "explain": "“VAR (Video Assistant Referee)” means: A team of officials in football who review footage of goals, penalties, red cards and mistaken identity"}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:match:b8303b93', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “TMO (Television Match Official)”?", "options": ["A team of officials in football who review footage of goals, penalties, red cards and mistaken identity", "A camera-based system used in tennis and cricket to track exactly where a ball landed or was heading", "An off-field official in rugby union who checks tries and serious foul play using video replays", "A cricket system letting a player challenge an umpire''s decision, checked using replays and ball-tracking"]}'::jsonb, '{"answer": 2, "explain": "“TMO (Television Match Official)” means: An off-field official in rugby union who checks tries and serious foul play using video replays"}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:match:7cd84f9b', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “DRS (Decision Review System)”?", "options": ["A camera-based system used in tennis and cricket to track exactly where a ball landed or was heading", "A cricket system letting a player challenge an umpire''s decision, checked using replays and ball-tracking", "A team of officials in football who review footage of goals, penalties, red cards and mistaken identity", "Cameras or sensors around a football goal that confirm whether the whole ball crossed the line"]}'::jsonb, '{"answer": 1, "explain": "“DRS (Decision Review System)” means: A cricket system letting a player challenge an umpire''s decision, checked using replays and ball-tracking"}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:match:c6e32364', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Goal-line technology”?", "options": ["A team of officials in football who review footage of goals, penalties, red cards and mistaken identity", "Cameras or sensors around a football goal that confirm whether the whole ball crossed the line", "An off-field official in rugby union who checks tries and serious foul play using video replays", "A cricket system letting a player challenge an umpire''s decision, checked using replays and ball-tracking"]}'::jsonb, '{"answer": 1, "explain": "“Goal-line technology” means: Cameras or sensors around a football goal that confirm whether the whole ball crossed the line"}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:match:8557d0d9', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Hawk-Eye (ball-tracking)”?", "options": ["A cricket system letting a player challenge an umpire''s decision, checked using replays and ball-tracking", "Cameras or sensors around a football goal that confirm whether the whole ball crossed the line", "A camera-based system used in tennis and cricket to track exactly where a ball landed or was heading", "An off-field official in rugby union who checks tries and serious foul play using video replays"]}'::jsonb, '{"answer": 2, "explain": "“Hawk-Eye (ball-tracking)” means: A camera-based system used in tennis and cricket to track exactly where a ball landed or was heading"}'::jsonb),
('sport-studies:5-1-3-technology-and-officiating:match:0a873f26', 'sport-studies', 'sport-studies:5-1-3-technology-and-officiating', '5.1.3 Technology and Officiating', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Photo-finish / electronic timing”?", "options": ["A team of officials in football who review footage of goals, penalties, red cards and mistaken identity", "A cricket system letting a player challenge an umpire''s decision, checked using replays and ball-tracking", "Cameras or sensors around a football goal that confirm whether the whole ball crossed the line", "Camera and automatic timing systems in athletics and swimming that separate finishes within hundredths of a second"]}'::jsonb, '{"answer": 3, "explain": "“Photo-finish / electronic timing” means: Camera and automatic timing systems in athletics and swimming that separate finishes within hundredths of a second"}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:exam:adfb69f6', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is the best example of technology enhancing the spectator experience, rather than officiating?", "options": ["A big screen replaying a great save for the crowd to enjoy again", "A goal-line sensor confirming the ball crossed the line for the referee", "A video review system overturning an on-pitch decision", "A sensor checking a serve landed inside the line for the umpire"], "hint": "Think about which option is mainly FOR the crowd''s enjoyment, not for helping an official decide.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — A big screen replaying a great save for the crowd to enjoy again.</strong></p>\n<ul>\n<li>This is mainly for the audience''s enjoyment and understanding of the moment.</li>\n<li>The other options are all mainly for helping an official reach a correct decision.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:mcq:ff2f28c3', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'mcq', 'mcq', 1, '{"question": "What does ''enhancing spectatorship'' mean in the context of technology in sport?", "options": ["Making the experience of watching sport better for the audience", "Making a performer''s competitive technique more accurate", "Making the playing surface much safer for participants", "Making it easier for an official to review a contested decision"]}'::jsonb, '{"answer": 0, "explain": "Spectatorship is about the watching experience; improving technique, surface safety and officiating accuracy are separate roles of technology in sport."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:mcq:e2d33937', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'mcq', 'mcq', 1, '{"question": "What is the main purpose of showing an action replay on a stadium''s big screen?", "options": ["To let the crowd see a key moment again and follow what happened", "To completely replace the need for any match officials working at the fixture", "To make the playing surface much more visible to the groundstaff", "To give performers a good deal of extra recovery time between events"]}'::jsonb, '{"answer": 0, "explain": "Big-screen replays are for the crowd''s benefit, not to remove officials, help groundstaff, or give performers recovery time."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:mcq:1dcb8b86', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'mcq', 'mcq', 1, '{"question": "A broadcaster adds an on-screen graphic showing a serve''s exact speed during a tennis match. This mainly helps...", "options": ["viewers at home understand more detail about what just happened", "the player serve the ball with much greater accuracy next time", "the official decide whether that particular serve was in or out", "the groundstaff prepare the court surface for the next game"]}'::jsonb, '{"answer": 0, "explain": "The graphic is broadcast information for the viewer''s understanding, not a tool for the player''s technique, the official''s decision, or court preparation."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:mcq:83e5a581', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'mcq', 'mcq', 1, '{"question": "Why might a fan use a live-stats app while watching a match on television?", "options": ["To see extra detail, such as player statistics, that the broadcast picture alone does not show", "To officially referee the match themselves from home using the app, fully replacing the real match officials", "To physically replace the stadium''s existing big-screen system", "To stop the broadcaster from showing any camera angles at all"]}'::jsonb, '{"answer": 0, "explain": "A stats app adds detail for the viewer''s own interest — it does not turn a fan into an official, replace stadium screens, or block camera angles."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:mcq:b88e1321', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of technology enhancing spectatorship, rather than officiating?", "options": ["A big screen replaying a great goal in slow motion for the crowd to enjoy again", "A video review system overturning a refereeing decision out on the pitch itself", "A sensor confirming to the official whether a ball crossed the goal line correctly", "A system checking a serve landed correctly inside the line for the umpire"]}'::jsonb, '{"answer": 0, "explain": "Replaying a moment for the crowd''s enjoyment is about the spectator experience; the other three examples are about helping an official reach a correct decision."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:mcq:265a1593', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'mcq', 'mcq', 1, '{"question": "A stadium adds giant screens purely so fans can watch replays and see review decisions explained. This is best described as technology used to...", "options": ["enhance the spectator experience", "enhance a performer''s competitive technique", "increase participant safety during the event", "support a governing body''s overall funding model"]}'::jsonb, '{"answer": 0, "explain": "Screens aimed at helping the crowd follow the action and decisions are enhancing spectatorship, not technique, safety, or funding."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tf:9a536a57', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tf', 'tf', 1, '{"question": "Technology that enhances spectatorship is mainly about improving the watching experience for fans."}'::jsonb, '{"answer": true, "explain": "That''s the definition — it is about the audience''s experience, whether in the stadium or watching remotely."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tf:114a47c6', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tf', 'tf', 1, '{"question": "A big screen replay in a stadium is mainly there to help a performer train more effectively."}'::jsonb, '{"answer": false, "explain": "Big-screen replays are aimed at the crowd''s experience, not at training a performer."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tf:5b92f85c', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tf', 'tf', 1, '{"question": "On-screen broadcast graphics, like a speed reading, can help viewers understand more detail about what happened."}'::jsonb, '{"answer": true, "explain": "Graphics add information the naked eye could not supply, helping the audience follow the action."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tf:03542bf7', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tf', 'tf', 1, '{"question": "A live-stats app used by a fan at home is an example of technology enhancing officiating."}'::jsonb, '{"answer": false, "explain": "A fan checking stats is about the spectator experience, not helping an official reach a decision."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tf:0edf7847', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tf', 'tf', 1, '{"question": "Multiple camera angles let broadcast viewers see an incident from more than one point of view."}'::jsonb, '{"answer": true, "explain": "Different camera positions around a venue give viewers a fuller picture of the same moment."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:tf:be6d3574', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'tf', 'tf', 1, '{"question": "Showing a review replay on a stadium''s big screen always removes the need for a match official."}'::jsonb, '{"answer": false, "explain": "The screen helps the crowd follow the decision — the official, not the screen, still makes the final call."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:learn:6925f3f7', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'learn', 'mcq', 1, '{"readingTitle": "What ''enhancing spectatorship'' means", "reading": "<h4>The idea</h4>\n<ul>\n<li><strong>Spectatorship</strong> is the experience of <strong>watching</strong> sport — whether that''s live inside a stadium or arena, or watching on television, a stream or a phone.</li>\n<li>One role of technology in sport is to make that watching experience <strong>better</strong>: clearer, more exciting, and easier to follow.</li>\n</ul>\n<h4>Not the same as performance, safety or officiating</h4>\n<ul>\n<li>This is a separate role from technology that helps a performer play better, technology that keeps people safe, or technology that helps an official make a correct decision.</li>\n<li>Here, the audience is the <strong>spectator</strong>, not the player or the official — so ask \"does this make the watching experience better for the crowd or the viewer?\"</li>\n</ul>\n<h4>Two settings to remember</h4>\n<ul>\n<li><strong>Inside the venue</strong> — fans in their seats at a stadium, arena or track.</li>\n<li><strong>Away from the venue</strong> — fans watching on TV, a stream, or checking an app.</li>\n</ul>", "question": "Which question best captures what ''technology to enhance spectatorship'' is about?", "options": ["Does this technology make the watching experience better for fans?", "Does this technology help a performer refine a competitive technique?", "Does this technology protect a participant''s body from serious injury?", "Does this technology help an official reach the correct decision?"]}'::jsonb, '{"answer": 0, "explain": "Spectatorship is about the audience''s experience of watching, not the performer''s technique, participant safety or officiating accuracy — those are separate roles of technology."}'::jsonb),
('sport-studies:5-1-4-technology-to-enhance-spectatorship:learn:f9c0241a', 'sport-studies', 'sport-studies:5-1-4-technology-to-enhance-spectatorship', '5.1.4 Technology to Enhance Spectatorship', 'learn', 'mcq', 1, '{"readingTitle": "Big screens and enhanced broadcast coverage", "reading": "<h4>Big screens inside the stadium</h4>\n<ul>\n<li>Large screens fitted inside stadia and arenas show <strong>action replays</strong> and <strong>slow-motion replays</strong> of key moments, so fans in the crowd can see incidents they may have missed live.</li>\n<li>When an official reviews a decision, the big screen can show fans the same replay the official is using, so the crowd can follow and understand an appeal rather than just waiting for an announcement.</li>\n<li>Example: at a cricket ground, the big screen might show a ball-tracking replay during a review, letting the crowd see why a batter was given out or not out.</li>\n</ul>\n<h4>Enhanced television broadcast coverage</h4>\n<ul>\n<li>Broadcasters use <strong>multiple camera angles</strong> around a venue, so viewers at home can see an incident from several different views rather than one fixed angle.</li>\n<li><strong>On-screen graphics</strong> add extra information over the picture — such as a trajectory line, a split-time comparison, or a graphic showing how close a decision was — helping viewers understand what is happening.</li>\n<li>Example: an on-screen speed reading during a tennis serve, or an onboard camera view during a cycling or motorsport event, both add detail a viewer could not otherwise see.</li>\n</ul>", "question": "Why might a stadium show fans the same review replay on its big screen that an official is using?", "options": ["So the crowd can follow and understand the decision, not just wait for an announcement", "So the official watching from the touchline can see the incident for the very first time ever", "So players on the pitch can argue with the decision much more easily", "So the stadium can reduce the total number of match officials used"]}'::jsonb, '{"answer": 0, "explain": "Sharing the replay lets the watching crowd follow the same evidence as the official, turning a wait into part of the spectator experience — it isn''t there to help the official see it first, encourage arguing, or cut staff."}'::jsonb)
